from collections import deque, defaultdict
from typing import List

class Solution:
    def shortestAlternatingPaths(self, n: int, redEdges: List[List[int]], blueEdges: List[List[int]]) -> List[int]:
        red_graph = defaultdict(list)
        blue_graph = defaultdict(list)

        for u, v in redEdges:
            red_graph[u].append(v)

        for u, v in blueEdges:
            blue_graph[u].append(v)

        answer = [-1] * n
        answer[0] = 0

        queue = deque([(0, 0, None)])  # node, distance, color of previous edge
        visited = set([(0, None)])

        while queue:
            node, dist, prev_color = queue.popleft()

            if prev_color != 'red' or prev_color is None:
                for neighbor in red_graph[node]:
                    if (neighbor, 'red') not in visited:
                        queue.append((neighbor, dist + 1, 'red'))
                        visited.add((neighbor, 'red'))
                        if answer[neighbor] == -1 or answer[neighbor] > dist + 1:
                            answer[neighbor] = dist + 1

            if prev_color != 'blue' or prev_color is None:
                for neighbor in blue_graph[node]:
                    if (neighbor, 'blue') not in visited:
                        queue.append((neighbor, dist + 1, 'blue'))
                        visited.add((neighbor, 'blue'))
                        if answer[neighbor] == -1 or answer[neighbor] > dist + 1:
                            answer[neighbor] = dist + 1

        return answer

